import{_ as t,o as a,c as r,ae as i}from"./chunks/framework.BEE-8mnG.js";const k=JSON.parse('{"title":"3-Bucket Capital Engineering","description":"","frontmatter":{},"headers":[],"relativePath":"capital/3-bucket.md","filePath":"capital/3-bucket.md"}'),o={name:"capital/3-bucket.md"};function n(u,e,c,l,s,d){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="_3-bucket-capital-engineering" tabindex="-1">3-Bucket Capital Engineering <a class="header-anchor" href="#_3-bucket-capital-engineering" aria-label="Permalink to &quot;3-Bucket Capital Engineering&quot;">​</a></h1><p><strong>&quot;투자의 성패는 &#39;좋은 종목&#39;이 아니라, &#39;자본의 유효성(Capital Efficiency)&#39;에 달려 있습니다.&quot;</strong> - WeJump Labs</p><hr><h2 id="🏗️-1-구조적-알파의-실체-3-bucket-model" tabindex="-1">🏗️ 1. 구조적 알파의 실체: 3-Bucket Model <a class="header-anchor" href="#🏗️-1-구조적-알파의-실체-3-bucket-model" aria-label="Permalink to &quot;🏗️ 1. 구조적 알파의 실체: 3-Bucket Model&quot;">​</a></h2><p>CBVR v2.3은 선물 복제(Futures Replication)를 통해 실제 자본의 극히 일부(15% 내외)만을 시장 노출에 사용합니다. 여기서 발생하는 <strong>80% 이상의 잉여 현금을 어떻게 활용하느냐</strong>가 위점프 전략의 핵심인 **&#39;구조적 알파&#39;**를 결정합니다.</p><p><img src="https://crowmag2.github.io/wejump/CBVR2.3_3Bucket.svg" alt="CBVR 3-Bucket Structure"></p><h3 id="🪣-bucket-1-active-margin-활성-증거금-15-20" tabindex="-1">🪣 Bucket 1: Active Margin (활성 증거금) [15~20%] <a class="header-anchor" href="#🪣-bucket-1-active-margin-활성-증거금-15-20" aria-label="Permalink to &quot;🪣 Bucket 1: Active Margin (활성 증거금) [15~20%]&quot;">​</a></h3><ul><li><strong>용도:</strong> KOSPI 200/NASDAQ 선물 계약 유지를 위한 가용 증거금.</li><li><strong>특징:</strong> 코어 엔진의 Beta 신호에 따라 실시간으로 노출도를 조절하는 최전선 기지입니다.</li></ul><h3 id="🪣-bucket-2-mdd-bumper-리스크-완충재-10-20" tabindex="-1">🪣 Bucket 2: MDD Bumper (리스크 완충재) [10~20%] <a class="header-anchor" href="#🪣-bucket-2-mdd-bumper-리스크-완충재-10-20" aria-label="Permalink to &quot;🪣 Bucket 2: MDD Bumper (리스크 완충재) [10~20%]&quot;">​</a></h3><ul><li><strong>용도:</strong> 시장의 극단적 변동성(Black Swan)에 대비한 상시 유동성 예비군.</li><li><strong>특징:</strong> 추가 증거금 납입(Margin Call 방어) 및 전략적 리밸런싱을 위한 심리적/물리적 안전판입니다.</li></ul><h3 id="🪣-bucket-3-realized-compounding-복리-실물화-60-🌟-핵심-🌟" tabindex="-1">🪣 Bucket 3: Realized Compounding (복리 실물화) [60%~] 🌟 핵심 🌟 <a class="header-anchor" href="#🪣-bucket-3-realized-compounding-복리-실물화-60-🌟-핵심-🌟" aria-label="Permalink to &quot;🪣 Bucket 3: Realized Compounding (복리 실물화) [60%~] 🌟 핵심 🌟&quot;">​</a></h3><ul><li><strong>용도:</strong> <strong>위점프 &#39;구조적 알파&#39;의 진짜 원천.</strong></li><li><strong>특징:</strong> 선물 복제로 확보된 정밀한 잉여 자금을 **실물 자산(PFIX, 금, 배당주 등)**으로 즉각 실물화하여, 코어 수익 위에 **이중 복리(Double Compounding)**를 쌓아올립니다.</li></ul><hr><h2 id="🛡️-2-왜-3-bucket인가" tabindex="-1">🛡️ 2. 왜 3-Bucket인가? <a class="header-anchor" href="#🛡️-2-왜-3-bucket인가" aria-label="Permalink to &quot;🛡️ 2. 왜 3-Bucket인가?&quot;">​</a></h2><p>일반적인 퀀트 전략은 모든 자산이 매크로 위험에 노출되어 있습니다. 하지만 3-Bucket 시스템은 **&#39;전략 수익&#39;**과 **&#39;자산 수익&#39;**을 분리하여 **생존성(Survival)**과 **수익성(Growth)**을 동시에 극대화합니다.</p><hr><blockquote><p><strong>Key Insight:</strong> &quot;Bucket 3로 옮겨진 수익만이 당신의 진짜 실력입니다. 나머지는 잠시 빌려온 **&#39;위험의 대가&#39;**일 뿐입니다.&quot; 🐯🐾</p></blockquote>',17)])])}const p=t(o,[["render",n]]);export{k as __pageData,p as default};
